#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define Sum(a,b) (sum[(i)]-sum[(j)-1])
using namespace std;
const int N=1e6+5;const long long INF=1e18;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag?-res:res;
}
long long dp[N],sum[N];int deq[N],h=1,t,A,B,C,n; 
double K[N];
inline double Cnt(int a,int b)
	{return 1.0*(1ll*A*(sum[a]*sum[a]-sum[b]*sum[b])-1ll*B*(sum[a]-sum[b])+dp[a]-dp[b])/(sum[a]-sum[b]);}
int main()
{
	n=read();A=read();B=read();C=read();rep(1,n,i)sum[i]=sum[i-1]+read();
	rep(1,n,i)
	{
		while(h<t&&K[t]<Cnt(deq[t],i-1))t--;
		K[t+1]=Cnt(deq[t],i-1);deq[++t]=i-1;
		while(h<t&&2ll*A*sum[i]<K[h+1])h++;
		dp[i]=dp[deq[h]]+1ll*A*(sum[i]-sum[deq[h]])*(sum[i]-sum[deq[h]])+1ll*B*(sum[i]-sum[deq[h]])+C;
	}
	printf("%lld",dp[n]);
}
